example.code:
# Active-passive VIP failover using keepalived + VRRP
# LB1 (active): holds VIP 10.0.0.10, priority 100
# LB2 (standby): priority 90, takes VIP if LB1 fails

# keepalived.conf on LB1:
vrrp_instance VI_1 {
    state MASTER
    interface eth0
    virtual_router_id 51
    priority 100
    advert_int 1
    virtual_ipaddress {
        10.0.0.10/24
    }
}

# keepalived.conf on LB2:
vrrp_instance VI_1 {
    state BACKUP
    interface eth0
    virtual_router_id 51
    priority 90
    advert_int 1
    virtual_ipaddress {
        10.0.0.10/24
    }
}
# Failover: LB1 stops sending VRRP advertisements → LB2 claims VIP within 3s

resource "aws_lb" "main" { name = "my-alb" internal = false load_balancer_type = "application" security_groups = [aws_security_group.alb.id]
# REQUIRED: subnets in at least 2 AZs for HA subnets = [ aws_subnet.public_az1.id, aws_subnet.public_az2.id, aws_subnet.public_az3.id, ]
enable_deletion_protection = true enable_http2 = true }
resource "aws_lb_target_group" "web" { name = "web-targets" port = 8080 protocol = "HTTP" vpc_id = var.vpc_id
health_check { healthy_threshold = 2 unhealthy_threshold = 3 interval = 30 path = "/health/ready" }
# Graceful backend removal deregistration_delay = 30 }

resource "aws_globalaccelerator_accelerator" "main" {
  name            = "my-accelerator"
  ip_address_type = "IPV4"
  enabled         = true

  attributes {
    flow_logs_enabled   = true
    flow_logs_s3_bucket = aws_s3_bucket.ga_logs.bucket
    flow_logs_s3_prefix = "ga-logs/"
  }
}

resource "aws_globalaccelerator_listener" "http" {
  accelerator_arn = aws_globalaccelerator_accelerator.main.id
  protocol        = "TCP"
  port_range {
    from_port = 443
    to_port   = 443
  }
}

resource "aws_globalaccelerator_endpoint_group" "us_east" {
  listener_arn          = aws_globalaccelerator_listener.http.id
  endpoint_group_region = "us-east-1"
  traffic_dial_percentage = 50

  endpoint_configuration {
    endpoint_id = aws_lb.us_east.arn
    weight      = 100
  }

  health_check_path             = "/health/ready"
  health_check_port             = 443
  health_check_protocol         = "HTTPS"
  health_check_interval_seconds = 30
  threshold_count               = 3
}

import signal import asyncio from fastapi import FastAPI, Response
app = FastAPI() is_shutting_down = False
@app.on_event("startup") async def setup_signal_handlers(): loop = asyncio.get_event_loop() loop.add_signal_handler(signal.SIGTERM, handle_sigterm)
def handle_sigterm(): global is_shutting_down is_shutting_down = True # Return 503 immediately on next health check # LB removes this backend within one health-check interval (10-30s) # In-flight requests continue to be processed during drain period
@app.get("/health/ready") async def readiness(response: Response): if is_shutting_down: response.status_code = 503 return {"status": "shutting_down"} return {"status": "healthy"}
